        function playRecording(recording) {
            if (isPlaying || !recording.notes.length) return;

            isPlaying = true;
            showPlaybackStatus(recording.name, 'recording');
            showToast('开始回放...');

            // 清理之前的定时器
            playbackTimeouts.forEach(id => clearTimeout(id));
            playbackTimeouts = [];

            recording.notes.forEach((noteData) => {
                const timeout = setTimeout(() => {
                    if (!isPlaying) return;
                    // 播放音频
                    playBellSound(noteData.freq);
                    // 触发强化动画
                    animateBellByNote(noteData.note, noteData.isSide);
                }, noteData.time);
