    // 特殊映射：使用侧敲来实现特定音符
    // B -> G的侧敲, F -> D的侧敲
    const sideHitMapping = {
        'B': { baseNote: 'G', sideNote: 'B' },
        'F': { baseNote: 'D', sideNote: 'F' }
    };

    // 琶音音符不需要映射，直接保留（因为和弦频率已经预定义好了）
    // 只映射普通编钟音符
    allNotes.forEach(note => {
        // 如果是琶音音符，跳过映射
        if (note.isArpeggio) {
            note.mapped = true;
            return;
        }

        // 解析原始音符名称（如 "C#4" -> noteName="C#", octave=4）
        const match = note.note.match(/^([A-G][#b]?)(\d+)$/);
        if (!match) return;

        const originalNoteName = match[1];
        const originalOctave = parseInt(match[2]);

        // 检查是否使用侧敲映射
        const sideMapping = sideHitMapping[originalNoteName];
        if (sideMapping) {
            // 使用侧敲：B->G侧敲, F->D侧敲
            const targetBellNote = `${sideMapping.baseNote}${originalOctave}`;
            const bellIndex = bellNotes.indexOf(targetBellNote);

            if (bellIndex !== -1) {
                note.note = targetBellNote;  // 存储基础音名（如 G4）
                note.freq = sideFreqs[targetBellNote];  // 使用侧敲频率！
                note.isSide = true;  // 标记为侧敲
                note.mapped = true;
                note.displayNote = sideMapping.sideNote + originalOctave;  // 用于显示的音符名
            }
            return;
        }

        // 映射到编钟音名
        const bellNoteName = chromaticToBell[originalNoteName] || originalNoteName;

        // 处理八度（B->C 和 A#->C 需要升八度）- 注意：B现在由侧敲处理了
        let finalOctave = originalOctave;
        if ((originalNoteName === 'A#' || originalNoteName === 'Bb') && bellNoteName === 'C') {
            finalOctave = originalOctave + 1;
        }

        // 构建编钟音符名称
        const targetBellNote = `${bellNoteName}${finalOctave}`;

        // 在编钟列表中查找
        const bellIndex = bellNotes.indexOf(targetBellNote);

        if (bellIndex !== -1) {
            // 找到匹配的编钟音
            note.note = targetBellNote;
            note.freq = bellFreqs[bellIndex];
            note.isSide = false;  // 正敲
            note.mapped = true;
        } else {
            // 未找到，使用频率最近匹配
            let closestIndex = 0;
            let closestDiff = Infinity;

            bellFreqs.forEach((freq, index) => {
                const diff = Math.abs(note.freq - freq);
                if (diff < closestDiff) {
                    closestDiff = diff;
                    closestIndex = index;
                }
            });

            note.note = bellNotes[closestIndex];
            note.freq = bellFreqs[closestIndex];
            note.isSide = false;
            note.mapped = true;
        }
    });

    // 过滤掉未成功映射的音符
    const validNotes = allNotes.filter(n => n.mapped);

    // 统计信息
    const arpeggioCount = validNotes.filter(n => n.isArpeggio).length / 4;

    return {
        name: `MIDI导入 ${new Date().toLocaleTimeString()}${arpeggioCount > 0 ? ` (${Math.floor(arpeggioCount)}个琶音)` : ''}`,
        bpm: bpm,
        notes: validNotes
    };
}

