                const wave1 = Math.sin(2 * Math.PI * fundamental * t) * 0.6 * env1;

                // 二次谐波 (正弦波) - 音量 0.3，2.4秒衰减
                const env2 = Math.exp(-t / 0.4);
                const wave2 = Math.sin(2 * Math.PI * harmonic2 * t) * 0.3 * env2;

                // 三次谐波 (三角波近似) - 音量 0.15，1.5秒衰减
                const env3 = Math.exp(-t / 0.25);
                // 三角波：用锯齿波的奇次谐波近似
                let triWave = 0;
                for (let h = 1; h <= 5; h += 2) {
