        function playClassicPiece(pieceId) {
            initAudio();

            // 如果正在播放，先停止
            if (isPlayingClassic) {
                stopClassicPiece();
                hidePlaybackStatus();
                // 如果点击的是当前播放的曲目，只停止不重新播放
                const clickedItem = document.querySelector(`[data-piece-id="${pieceId}"]`);
                if (clickedItem && clickedItem.classList.contains('playing')) {
                    return;
                }
            }

            const piece = classicPieces[pieceId];
            if (!piece) return;

            isPlayingClassic = true;
            showPlaybackStatus(piece.name, 'classic');
            showToast(`正在播放：${piece.name}`);

            // 更新UI状态
            document.querySelectorAll('.classic-item').forEach(item => {
                item.classList.remove('playing');
            });
            document.querySelector(`[data-piece-id="${pieceId}"]`)?.classList.add('playing');

            // 播放每个音符
            piece.notes.forEach((noteData, index) => {
                const timeout = setTimeout(() => {
                    if (!isPlayingClassic) return;

                    const freq = getFreqByNote(noteData.note, noteData.isSide);
                    if (freq) {
                        // 播放音频
                        playBellSound(freq);

                        // 触发对应编钟的动画
                        animateBellByNote(noteData.note, noteData.isSide);
                    }

                    // 最后一个音符播放完后重置状态
                    if (index === piece.notes.length - 1) {
                        const resetTimeout = setTimeout(() => {
                            stopClassicPiece();
                            hidePlaybackStatus();
                        }, 1000);
                        classicTimeouts.push(resetTimeout);
                    }
                }, noteData.time);

                classicTimeouts.push(timeout);
            });
        }

        function animateBellByNote(noteName, isSide = false) {
            // 查找对应的编钟元素
            const bells = document.querySelectorAll('.bell');
            let targetBell = null;

            for (const bell of bells) {
                const bellNote = bell.dataset.note;
                const bellSideNote = bell.dataset.sideNote;

                if ((!isSide && bellNote === noteName) || (isSide && bellSideNote === noteName)) {
                    targetBell = bell;
                    break;
                }
            }

            if (targetBell) {
                // 添加强化动画
                targetBell.classList.add('bell-swing-strong');
                targetBell.classList.add('bell-glow');
                targetBell.classList.add('bell-playing');

                // 击槌动画
                const mallet = targetBell.querySelector('.mallet-hit');
                if (mallet) {
                    mallet.textContent = isSide ? '🔨·' : '·🔨';
                    mallet.classList.add('show');
                    setTimeout(() => mallet.classList.remove('show'), 200);
                }

                // 移除动画类
                setTimeout(() => {
                    targetBell.classList.remove('bell-swing-strong');
                    targetBell.classList.remove('bell-glow');
                    targetBell.classList.remove('bell-playing');
                }, 600);
            }
        }

        function stopClassicPiece() {
            isPlayingClassic = false;
