// v1.8.4: 删除经典曲目
function deleteClassicPiece(pieceId) {
    if (!confirm('确定要删除这首经典曲目吗？')) return;

    // 从 classicPieces 中删除
    delete classicPieces[pieceId];

    // 从 localStorage 中删除
    const saved = localStorage.getItem('bianzhong_custom_classics');
    if (saved) {
        try {
            const customPieces = JSON.parse(saved);
            delete customPieces[pieceId];
            localStorage.setItem('bianzhong_custom_classics', JSON.stringify(customPieces));
        } catch (e) {
            console.error('删除经典曲目失败:', e);
        }
    }

    showToast('已删除经典曲目');
    renderClassicList(); // 重新渲染列表
}

